<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('system_errors.manage');$pdo=obtenerConexion();$estado=(string)($_GET['estado']??'');$categoria=(string)($_GET['categoria']??'');$pagina=max(1,(int)($_GET['pagina']??1));$lim=25;$where=' WHERE 1';$pa=[];if(in_array($estado,['nuevo','revisando','resuelto'],true)){$where.=' AND estado=:e';$pa['e']=$estado;}if(in_array($categoria,['pago','webhook','dte','correo','stock','base_datos','sistema'],true)){$where.=' AND categoria=:c';$pa['c']=$categoria;}$q=$pdo->prepare('SELECT COUNT(*) FROM errores_sistema'.$where);$q->execute($pa);$total=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT * FROM errores_sistema'.$where.' ORDER BY ultima_ocurrencia_at DESC LIMIT :lim OFFSET :off');foreach($pa as$k=>$v)$q->bindValue(':'.$k,$v);$q->bindValue(':lim',$lim,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$lim,PDO::PARAM_INT);$q->execute();$filas=$q->fetchAll();cmsCabecera('Errores operativos','errores/index.php','Errores relevantes agrupados; no incluye warnings menores ni secretos.');?>
<div class="card card-rounded"><div class="card-body"><form class="row g-2 mb-4"><div class="col-md-4"><select class="form-select" name="estado"><option value="">Todos los estados</option><?php foreach(['nuevo','revisando','resuelto'] as$e):?><option <?=$estado===$e?'selected':''?>><?=$e?></option><?php endforeach;?></select></div><div class="col-md-4"><select class="form-select" name="categoria"><option value="">Todas las categorías</option><?php foreach(['pago','webhook','dte','correo','stock','base_datos','sistema'] as$c):?><option <?=$categoria===$c?'selected':''?>><?=$c?></option><?php endforeach;?></select></div><div class="col-md-2"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form><div class="table-responsive"><table class="table"><thead><tr><th>Categoría</th><th>Mensaje</th><th>Estado</th><th>Repeticiones</th><th>Última vez</th><th></th></tr></thead><tbody><?php foreach($filas as$e):?><tr><td><?=atenea_e($e['categoria'])?></td><td><?=atenea_e($e['mensaje'])?><small class="d-block"><?=atenea_e($e['modulo'])?></small></td><td><?=atenea_e($e['estado'])?></td><td><?=(int)$e['ocurrencias']?></td><td><?=date('d/m/Y H:i',strtotime($e['ultima_ocurrencia_at']))?></td><td><a class="btn btn-sm btn-outline-primary" href="detalle.php?id=<?=$e['id']?>">Revisar</a></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="6" class="text-center py-5">No hay errores para estos filtros.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();
